/// GET v1/{+parent}/trial:subscribe
/// Subscribes to a trial for a project
///
/// Returns `ClientRequestBuilder` for customization.
/// Use `backupdr_projects_locations_trial_subscribe_execute()` to send, or `backupdr_projects_locations_trial_subscribe` for simplest API.

pub fn backupdr_projects_locations_trial_subscribe_builder(
    client: &SimpleHttpClient,
    parent: &str,
    body: &SubscribeTrialRequest,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {
    // Build URL
    let url = format!(
        "https://api.example.comv1/{+parent}/trial:subscribe",
        parent,
    );

    // Build request
    client
        .get(&url)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
        .body_json(body)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
}

/// GET v1/{+parent}/trial:subscribe
/// Subscribes to a trial for a project
///
/// Takes a `ClientRequestBuilder`, builds and executes the request.
/// For customization, use `backupdr_projects_locations_trial_subscribe_builder()` then pass to this function.
///
/// # Arguments
///
/// * `builder` - ClientRequestBuilder from backupdr_projects_locations_trial_subscribe_builder()
///
/// # Errors
///
/// Returns an error if the request cannot be built.

pub fn backupdr_projects_locations_trial_subscribe_execute(
    builder: ClientRequestBuilder<SystemDnsResolver>,
) -> Result<
    impl StreamIterator<D = Result<ApiResponse<Trial>, ApiError>, P = ApiPending> + Send + 'static,
    ApiError,
> {
    // Get SendRequestTask from builder
    let task = builder
        .build_send_request()
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
        .map_ready(|intro| match intro {
            RequestIntro::Success { stream, status } => {
                let headers = status.headers().clone();

                if !status.is_success() {
                    return Err(ApiError::HttpStatus {
                        code: status.as_u16(),
                        headers,
                    });
                }

                let body = body_reader::collect_string(stream);
                let parsed: Trial = serde_json::from_str(&body)
                    .map_err(|e| ApiError::ParseFailed(e.to_string()))?;

                Ok(ApiResponse {
                    status: status.as_u16(),
                    headers,
                    body: parsed,
                })
            }
            RequestIntro::Failed(e) => Err(ApiError::RequestSendFailed(e.to_string())),
        })
        .map_pending(|_| ApiPending::Sending);

    // Convert TaskIterator to StreamIterator
    execute(task, None).map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
}

